dslRule:
/*!id: status-util-newstatus-overload>
<!description: Update StatusUtil.newStatus to use a List of statuses and null throwable.>
<!severity: info>
<!minJavaVersion: 9>
<!tags: api-migration, error-handling>

org.eclipse.core.runtime.StatusUtil.newStatus($status, $msg) :: sourceVersionGE(9)
=> org.eclipse.core.runtime.StatusUtil.newStatus(java.util.List.of($status), $msg, null)
;;
// The change to StatusManager.getManager().handle to include StatusManager.LOG
// using a bitwise OR operator (StatusManager.SHOW | StatusManager.LOG) is not
// supported by the current TriggerPattern DSL, rendering the full transformation impossible.
